// // This module synchronously clears and loads the register on the negative edge of clk
module register (
        input clk,
        input clear,
        input load,
        input [7:0] data,
        output reg [7:0] q);always @(posedge clk) begin
	if (clear)
		q <= 8'b00000000;
	else if (load)
		q <= data;
end

endmodule
